#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;
    unordered_map<int, long long> count;
    count[0] = 1;
    long long ans = 0;
    for(int num : nums){
        unordered_map<int, long long> new_count;
        for(auto& pair : count){
            new_count[pair.first] += pair.second;
            new_count[pair.first + num] += pair.second;
        }
        count = new_count;
    }
    ans = count[target];
    cout << ans;
}
